patch:
--- a/parity_checker.sv
+++ b/parity_checker.sv
@@ -1,10 +1,10 @@
 module parity_checker_64bit(
     input [63:0] data_in,
     input enable,
     output reg parity_out
 );

-    always_comb begin
+    always @(*) begin
         if (enable)
             parity_out = ^data_in;
         else
             parity_out = 1'b0;
     end

before_code:
module parity_checker_64bit(
    input [63:0] data_in,
    input enable,
    output reg parity_out
 );

    always_comb begin
        if (enable)
            parity_out = ^data_in;
        else
            parity_out = 1'b0;
    end

endmodule

after_code:
module parity_checker_64bit(
    input [63:0] data_in,
    input enable,
    output reg parity_out
 );

    always @(*) begin
        if (enable)
            parity_out = ^data_in;
        else
            parity_out = 1'b0;
    end

endmodule
